export type Cell = [x: number, y: number];

function key(x: number, y: number): string {
  return `${x},${y}`;
}

function countLiveNeighbors(x: number, y: number, alive: Set<string>): number {
  let count = 0;
  for (let dx = -1; dx <= 1; dx++) {
    for (let dy = -1; dy <= 1; dy++) {
      if (dx === 0 && dy === 0) continue;
      if (alive.has(key(x + dx, y + dy))) count++;
    }
  }
  return count;
}

export function nextGeneration(liveCells: Cell[]): Cell[] {
  const alive = new Set(liveCells.map(([x, y]) => key(x, y)));
  const survivors: Cell[] = [];
  for (const [x, y] of liveCells) {
    const n = countLiveNeighbors(x, y, alive);
    if (n === 2 || n === 3) survivors.push([x, y]);
  }
  return survivors;
}

