export function nextGeneration(liveCells: Cell[]): Cell[] {
  const alive = new Set(liveCells.map(([x, y]) => cellKey(x, y)));
  const survivors = liveCells.filter((cell) => survives(cell, alive));

  const candidateKeys = new Set<string>();
  const candidates: Cell[] = [];
  for (const [x, y] of liveCells) {
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      const nx = x + dx;
      const ny = y + dy;
      const k = cellKey(nx, ny);
      if (alive.has(k)) continue;
      if (candidateKeys.has(k)) continue;
      candidateKeys.add(k);
      candidates.push([nx, ny]);
    }
  }
  const births = candidates.filter(([x, y]) => countLiveNeighbors(x, y, alive) === 3);

  return [...survivors, ...births];
}

